function toggleNavbar(){const menu=document.getElementById("navbarMenu"),toggle=document.querySelector(".navbar-toggle");if(menu){const isActive=menu.classList.toggle("active");toggle&&toggle.setAttribute("aria-expanded",isActive?"true":"false")}}function toggleMenu(){toggleNavbar()}document.addEventListener("click",function(event){const navbar=document.querySelector(".navbar"),menu=document.getElementById("navbarMenu"),toggle=document.querySelector(".navbar-toggle");navbar&&menu&&toggle&&!navbar.contains(event.target)&&menu.classList.contains("active")&&(menu.classList.remove("active"),toggle&&toggle.setAttribute("aria-expanded","false"))});function setActiveMenuItem(){const currentPath=window.location.pathname;document.querySelectorAll(".navbar-menu a").forEach(item=>{item.classList.remove("active");const href=item.getAttribute("href");(currentPath==="/"&&(href==="#home"||href==="/")||currentPath.startsWith("/activities")&&href==="/activities"||currentPath==="/members"&&href==="/members"||currentPath==="/login"&&href==="/login"||currentPath.startsWith("/genealogy")&&href==="/genealogy"||currentPath.startsWith("/contact")&&href==="/contact"||currentPath.startsWith("/documents")&&href==="/documents")&&item.classList.add("active")})}document.addEventListener("DOMContentLoaded",function(){setActiveMenuItem()});function stripDuplicateAliasLabel(text){return text==null||text===""?"":String(text).replace(/^(\s*Tên\s+thường\s+gọi\s*:\s*)+/i,"").trim()}function escapeHtml(text){if(text==null)return"";const div=document.createElement("div");return div.textContent=String(text),div.innerHTML}function formatDate(dateStr){if(!dateStr)return"";try{return new Date(dateStr).toLocaleDateString("vi-VN",{year:"numeric",month:"long",day:"numeric"})}catch{return dateStr}}function formatDateTime(dateStr){if(!dateStr)return"";try{return new Date(dateStr).toLocaleDateString("vi-VN",{year:"numeric",month:"long",day:"numeric",hour:"2-digit",minute:"2-digit"})}catch{return dateStr}}async function fetchJson(url,options={}){const res=await fetch(url,options),contentType=res.headers.get("Content-Type")||"",text=await res.text();if(!res.ok)throw console.error("HTTP error for",url,res.status,text),new Error(`HTTP ${res.status} khi gọi ${url}`);if(!contentType.includes("application/json"))throw console.error("Non-JSON response for",url,"contentType =",contentType,"body =",text.slice(0,200)),new Error("Phản hồi không phải JSON. Server trả về HTML hoặc nội dung khác.");try{return JSON.parse(text)}catch(e){throw console.error("JSON parse error for",url,"body =",text.slice(0,200)),e}}
